import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { createStaff } from "../../api/adminUserApi";
import UserForm from "./UserForm";

export default function CreateUser() {
  const navigate = useNavigate();
  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState({ name: "", email: "", password: "", role: "staff", isDeleted: false });

  const onChange = (event) => {
    const { name, value } = event.target;
    setForm((current) => ({ ...current, [name]: value }));
  };

  const submit = async (event) => {
    event.preventDefault();
    setSaving(true);
    try {
      await createStaff({ name: form.name, email: form.email, password: form.password, role: form.role });
      alert("Staff created");
      navigate("/admin/staff");
    } catch (err) {
      alert(err.response?.data?.message || "Failed");
    } finally {
      setSaving(false);
    }
  };

  return (
    <UserForm
      title="Create Staff / Manager"
      subtitle=""
      modeLabel="New Team Account"
      form={form}
      onChange={onChange}
      onSubmit={submit}
      saving={saving}
      submitLabel="Create User"
      onCancel={() => navigate("/admin/staff")}
      showPassword
    />
  );
}
